mod gsd_process;
mod gsd_query;
mod gsd_resolve;
mod gsd_rpc;
mod gsd_watcher;
mod project_registry;

use std::sync::Arc;
use tauri::Emitter;
use tokio::sync::Mutex;

use gsd_process::GsdProcess;
use gsd_resolve::resolve_gsd_binary;
use gsd_rpc::RpcCommand;
use gsd_watcher::GsdFileWatcher;

/// Tauri managed state holding the active GSD process and file watcher.
pub struct GsdState {
    process: Arc<Mutex<Option<GsdProcess>>>,
    watcher: Arc<Mutex<Option<GsdFileWatcher>>>,
}

impl GsdState {
    fn new() -> Self {
        GsdState {
            process: Arc::new(Mutex::new(None)),
            watcher: Arc::new(Mutex::new(None)),
        }
    }
}

/// Start a new GSD RPC session. Resolves the gsd binary, stops any existing
/// process, and spawns a fresh `gsd --mode rpc --project <path>`.
#[tauri::command]
async fn start_gsd_session(
    project_path: String,
    state: tauri::State<'_, GsdState>,
    app: tauri::AppHandle,
) -> Result<(), String> {
    let binary = resolve_gsd_binary()?;

    let mut guard = state.process.lock().await;

    // Stop any existing process first
    if let Some(mut existing) = guard.take() {
        let _ = existing.stop().await;
    }

    let process = GsdProcess::spawn(&binary, &project_path, app.clone()).await?;
    *guard = Some(process);

    // Spawn a background task to monitor for process exit and emit event
    let process_ref = state.process.clone();
    let app_exit = app.clone();
    tokio::spawn(async move {
        loop {
            tokio::time::sleep(std::time::Duration::from_millis(500)).await;
            let mut guard = process_ref.lock().await;
            if let Some(proc) = guard.as_mut() {
                if !proc.is_running() {
                    let _ = app_exit.emit(
                        "gsd-process-exit",
                        gsd_process::GsdExitPayload {
                            code: None, // process already reaped by is_running()
                            timestamp: gsd_process::unix_timestamp_ms(),
                        },
                    );
                    guard.take(); // clean up
                    break;
                }
            } else {
                break; // no process to monitor
            }
        }
    });

    Ok(())
}

/// Stop the active GSD RPC session.
#[tauri::command]
async fn stop_gsd_session(
    state: tauri::State<'_, GsdState>,
) -> Result<(), String> {
    let mut guard = state.process.lock().await;
    if let Some(mut process) = guard.take() {
        process.stop().await
    } else {
        Ok(()) // No process running — not an error
    }
}

/// Send an RPC command to the running GSD process.
///
/// `command` is a JSON string that deserializes into an `RpcCommand`.
#[tauri::command]
async fn send_gsd_command(
    command: String,
    state: tauri::State<'_, GsdState>,
) -> Result<(), String> {
    let cmd: RpcCommand = serde_json::from_str(&command)
        .map_err(|e| format!("Invalid RPC command JSON: {}", e))?;

    let guard = state.process.lock().await;
    if let Some(process) = guard.as_ref() {
        process.send_command(&cmd).await
    } else {
        Err("No GSD process is running. Call start_gsd_session first.".to_string())
    }
}

/// Query GSD project state via headless query command.
/// Returns a `QuerySnapshot` matching the frontend `GsdState` interface.
#[tauri::command]
async fn query_gsd_state(
    project_path: String,
) -> Result<gsd_query::QuerySnapshot, String> {
    gsd_query::run_headless_query(&project_path).await
}

/// List GSD projects in a directory by scanning for `.gsd/` subdirectories.
/// Returns a `Vec<ProjectInfo>` matching the frontend `ProjectInfo` interface.
#[tauri::command]
async fn list_projects(
    scan_path: String,
) -> Result<Vec<gsd_query::ProjectInfo>, String> {
    gsd_query::list_projects_in_dir(&scan_path)
}

/// Start watching a project's `.gsd/` directory for file changes.
/// Emits `gsd-file-changed` events when STATE.md, metrics.json, or
/// *-ROADMAP.md files change. Debounces rapid changes (500ms window).
#[tauri::command]
async fn start_file_watcher(
    project_path: String,
    state: tauri::State<'_, GsdState>,
    app: tauri::AppHandle,
) -> Result<(), String> {
    let mut guard = state.watcher.lock().await;

    // Stop any existing watcher first
    if let Some(existing) = guard.take() {
        existing.stop();
    }

    let watcher = GsdFileWatcher::start_tauri(&project_path, app)?;
    *guard = Some(watcher);
    Ok(())
}

/// Stop the active file watcher.
#[tauri::command]
async fn stop_file_watcher(
    state: tauri::State<'_, GsdState>,
) -> Result<(), String> {
    let mut guard = state.watcher.lock().await;
    if let Some(watcher) = guard.take() {
        watcher.stop();
    }
    Ok(())
}

// ---------------------------------------------------------------------------
// Project registry commands
// ---------------------------------------------------------------------------

/// Get all saved projects from the persistent registry.
#[tauri::command]
async fn get_saved_projects(
    app: tauri::AppHandle,
) -> Result<Vec<project_registry::SavedProject>, String> {
    let registry = project_registry::load(&app)?;
    Ok(registry.projects)
}

/// Add a project to the registry by its filesystem path.
/// Validates it contains a `.gsd/` directory.
#[tauri::command]
async fn add_project(
    project_path: String,
    description: Option<String>,
    app: tauri::AppHandle,
) -> Result<project_registry::SavedProject, String> {
    project_registry::add_project(&app, &project_path, description)
}

/// Remove a project from the registry by its ID.
#[tauri::command]
async fn remove_project(
    project_id: String,
    app: tauri::AppHandle,
) -> Result<(), String> {
    project_registry::remove_project(&app, &project_id)
}

#[cfg_attr(mobile, tauri::mobile_entry_point)]
pub fn run() {
    tauri::Builder::default()
        .plugin(tauri_plugin_dialog::init())
        .manage(GsdState::new())
        .invoke_handler(tauri::generate_handler![
            start_gsd_session,
            stop_gsd_session,
            send_gsd_command,
            query_gsd_state,
            list_projects,
            start_file_watcher,
            stop_file_watcher,
            get_saved_projects,
            add_project,
            remove_project
        ])
        .run(tauri::generate_context!())
        .expect("error while running tauri application");
}

use serde::{Deserialize, Serialize};
use std::path::Path;
use std::process::Stdio;

use crate::gsd_resolve::resolve_gsd_binary;

// ---------------------------------------------------------------------------
// Structs — field names match frontend GsdState / ProjectInfo via camelCase
// ---------------------------------------------------------------------------

/// Snapshot of GSD project state, returned by `gsd headless query`.
/// Matches the frontend `GsdState` interface in `gsd-client.ts`.
#[derive(Debug, Clone, Serialize, Deserialize, PartialEq)]
#[serde(rename_all = "camelCase")]
pub struct QuerySnapshot {
    pub current_milestone: Option<String>,
    pub active_tasks: u32,
    pub total_cost: f64,
}

/// A discovered GSD project directory.
/// Matches the frontend `ProjectInfo` interface in `gsd-client.ts`.
#[derive(Debug, Clone, Serialize, Deserialize, PartialEq)]
#[serde(rename_all = "camelCase")]
pub struct ProjectInfo {
    pub id: String,
    pub name: String,
    pub path: String,
}

// ---------------------------------------------------------------------------
// Headless query execution
// ---------------------------------------------------------------------------

/// Run `gsd headless query --project <path> --format json` and parse output
/// into a `QuerySnapshot`. Returns a descriptive error on any failure.
pub async fn run_headless_query(project_path: &str) -> Result<QuerySnapshot, String> {
    let binary = resolve_gsd_binary()?;

    let mut cmd = tokio::process::Command::new(&binary);
    cmd.args(["headless", "query", "--project", project_path, "--format", "json"])
        .stdin(Stdio::null())
        .stdout(Stdio::piped())
        .stderr(Stdio::piped());

    // On Windows, prevent a console window from flashing
    #[cfg(windows)]
    {
        use std::os::windows::process::CommandExt;
        cmd.creation_flags(0x08000000); // CREATE_NO_WINDOW
    }

    let output = cmd
        .output()
        .await
        .map_err(|e| format!("Failed to spawn gsd binary at '{}': {}", binary.display(), e))?;

    if !output.status.success() {
        let stderr = String::from_utf8_lossy(&output.stderr);
        let code = output.status.code().map_or("unknown".to_string(), |c| c.to_string());
        return Err(format!(
            "gsd headless query exited with code {}: {}",
            code,
            stderr.trim()
        ));
    }

    let stdout = String::from_utf8_lossy(&output.stdout);
    serde_json::from_str::<QuerySnapshot>(stdout.trim()).map_err(|e| {
        format!(
            "Failed to parse gsd headless query JSON output: {}. Raw output: '{}'",
            e,
            stdout.chars().take(200).collect::<String>()
        )
    })
}

/// Parse raw JSON string into a `QuerySnapshot`. Exposed for unit testing.
pub fn parse_query_json(json: &str) -> Result<QuerySnapshot, String> {
    serde_json::from_str::<QuerySnapshot>(json.trim()).map_err(|e| {
        format!(
            "Failed to parse gsd headless query JSON output: {}. Raw output: '{}'",
            e,
            json.chars().take(200).collect::<String>()
        )
    })
}

// ---------------------------------------------------------------------------
// Project directory scanning
// ---------------------------------------------------------------------------

/// Scan `scan_path` for subdirectories that contain a `.gsd/` child directory.
/// Returns a `ProjectInfo` for each match.
pub fn list_projects_in_dir(scan_path: &str) -> Result<Vec<ProjectInfo>, String> {
    let dir = Path::new(scan_path);
    if !dir.is_dir() {
        return Err(format!("Scan path is not a directory: {}", scan_path));
    }

    let entries = std::fs::read_dir(dir)
        .map_err(|e| format!("Failed to read directory '{}': {}", scan_path, e))?;

    let mut projects = Vec::new();

    for entry in entries {
        let entry = entry
            .map_err(|e| format!("Failed to read directory entry: {}", e))?;
        let path = entry.path();

        if path.is_dir() && path.join(".gsd").is_dir() {
            let dir_name = entry
                .file_name()
                .to_string_lossy()
                .to_string();
            let abs_path = std::fs::canonicalize(&path)
                .unwrap_or_else(|_| path.clone())
                .to_string_lossy()
                .to_string();

            projects.push(ProjectInfo {
                id: dir_name.clone(),
                name: dir_name,
                path: abs_path,
            });
        }
    }

    Ok(projects)
}

